21	type Item = { type: string; cursed?: boolean; enchantment?: number; material?: string };
22	
23	const basePremiumFor = (item: Item): number => {
24	  if (!(item.type in BASE_PREMIUM_BY_TYPE)) {
25	    throw new Error(`Unknown item type: ${item.type}`);
26	  }
27	  return BASE_PREMIUM_BY_TYPE[item.type];
28	};
29	
30	const isHighlyEnchanted = (item: Item): boolean =>
31	  (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD;
32	
33	const surchargeRate = (item: Item): number =>
34	  (item.cursed ? CURSE_SURCHARGE_RATE : 0) +
35	  (isHighlyEnchanted(item) ? HIGH_ENCHANTMENT_SURCHARGE_RATE : 0);
36	
37	const mainItemPremium = (item: Item): number => {
38	  const base = basePremiumFor(item);
39	  return base + base * surchargeRate(item);
40	};
41	
42	const isComponent = (item: Item): boolean => COMPONENT_TYPES.includes(item.type);
43	
44	const componentGroupPremium = (group: Item[]): number =>
45	  group.length === COMPONENT_BLOCK_SIZE
46	    ? COMPONENT_BLOCK_PREMIUM
47	    : group.reduce((sum, item) => sum + basePremiumFor(item), 0);
48	
49	const groupComponentsByType = (items: Item[]): Item[][] => {
50	  const groups: Record<string, Item[]> = {};
51	  for (const item of items) {
52	    (groups[item.type] ||= []).push(item);
53	  }
54	  return Object.values(groups);
55	};
