76	export function quote(customer: Customer, items: Item[]): number {
77	  const itemsTotal = sumItemsPremium(items, mainItemPremium);
78	  const policyBase = sumItemsPremium(items, basePremiumFor);
79	  const loyaltyDiscount = policyBase * loyaltyDiscountRate(customer);
80	  const followUpDiscount = policyBase * followUpDiscountRate(customer);
81	  const firstInsuranceSurcharge = policyBase * FIRST_INSURANCE_SURCHARGE_RATE;
82	  const total = itemsTotal - loyaltyDiscount - followUpDiscount + firstInsuranceSurcharge + PROCESSING_FEE;
83	  return Math.ceil(total);
84	}
