93	export function claim(items: Item[], incident: Incident): number {
94	  const total = incident.damages.reduce((sum, damage) => {
95	    const item = items.find((i) => i.type === damage.itemType);
96	    if (!item) {
97	      throw new Error(`Item type not in policy: ${damage.itemType}`);
98	    }
99	    const rate =
100	      (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_CLAIM_THRESHOLD
101	        ? HIGH_ENCHANTMENT_REIMBURSEMENT_RATE
102	        : 1;
103	    return sum + (damage.amount * rate - DEDUCTIBLE_PER_DAMAGE);
104	  }, 0);
105	  return Math.floor(total);
106	}
